export class Login_model {
  constructor() {
    this.state = {
      web_admin: {
        loading: false,
        failed_login: false,
        logged_in: false,
      },
      board_member_login: {
        loading: false,
        failed_login: false,
        logged_in: false,
      },
    };
    this.listeners = [];
  }

  setState = (newState) => {
    this.state = { ...this.state, ...newState };
    this.notifyListeners();
    console.log(this.state);
    return this.state;
  };

  getState = (stateName) => {
    if (this.state[stateName]) {
      return this.state[stateName];
    } else {
      console.log("no state exists");
    }
  };

  registerListener = (listener) => {
    this.listeners.push(listener);
    listener(this.state);
  };

  notifyListeners = () => {
    this.listeners.forEach((listener) => {
      listener(this.state);
    });
  };

  website_admin_login = (password) => {
    if (process.env.NODE_ENV === "production") {
      this.setState({
        web_admin: {
          loading: true,
          failed_login: false,
          logged_in: false,
        },
      });

      fetch("https://abbeyroad.org.uk/api/login-page/website_admin_login", {
        method: "post",
        headers: {
          "Content-Type": "application/json",
        },
        credentials: "include",
        body: JSON.stringify({
          password: password,
        }),
      })
        .then((res) => {
          return res.json();
        })
        .then((result) => {
          if (result.status) {
            this.setState({
              web_admin: {
                loading: false,
                failed_login: false,
                logged_in: true,
              },
            });
          } else {
            this.setState({
              web_admin: {
                loading: false,
                failed_login: true,
                logged_in: false,
              },
            });
          }
        })
        .catch((err) => {
          console.log(err);

          this.setState({
            web_admin: {
              loading: false,
              failed_login: true,
              logged_in: false,
            },
          });
        });
    } else {
      this.setState({
        web_admin: {
          loading: true,
          failed_login: false,
          logged_in: false,
        },
      });

      fetch("http://localhost:3001/api/login-page/website_admin_login", {
        method: "post",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          password: password,
        }),
      })
        .then((res) => {
          return res.json();
        })
        .then((result) => {
          if (result.status) {
            this.setState({
              web_admin: {
                loading: false,
                failed_login: false,
                logged_in: true,
              },
            });
          } else {
            this.setState({
              web_admin: {
                loading: false,
                failed_login: true,
                logged_in: false,
              },
            });
          }
        })
        .catch((err) => {
          console.log(err);

          this.setState({
            web_admin: {
              loading: false,
              failed_login: true,
              logged_in: false,
            },
          });
        });
    }
  };

  board_member_login = (username, password) => {
    if (process.env.NODE_ENV === "production") {
      this.setState({
        board_member_login: {
          loading: true,
          failed_login: false,
          logged_in: false,
        },
      });

      fetch("https://abbeyroad.org.uk/api/login-page/board_members_login", {
        method: "post",
        headers: {
          "Content-Type": "application/json",
        },
        credentials: "include",
        body: JSON.stringify({
          username: username,
          password: password,
        }),
      })
        .then((res) => {
          return res.json();
        })
        .then((data) => {
          if (data.status) {
            console.log(data);
            this.setState({
              board_member_login: {
                loading: false,
                failed_login: false,
                logged_in: true,
              },
            });
          } else {
            this.setState({
              board_member_login: {
                loading: false,
                failed_login: true,
                logged_in: false,
              },
            });
          }
        })
        .catch((err) => {
          this.setState({
            board_member_login: {
              loading: false,
              failed_login: true,
              logged_in: false,
            },
          });
        });
    } else {
      this.setState({
        board_member_login: {
          loading: true,
          failed_login: false,
          logged_in: false,
        },
      });

      fetch("http://localhost:3001/api/login-page/board_members_login", {
        method: "post",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          username: username,
          password: password,
        }),
      })
        .then((res) => {
          return res.json();
        })
        .then((data) => {
          if (data.status) {
            this.setState({
              board_member_login: {
                loading: false,
                failed_login: false,
                logged_in: true,
              },
            });
          } else {
            this.setState({
              board_member_login: {
                loading: false,
                failed_login: true,
                logged_in: false,
              },
            });
          }
        })
        .catch((err) => {
          this.setState({
            board_member_login: {
              loading: false,
              failed_login: true,
              logged_in: false,
            },
          });
        });
    }
  };
}
