export class Login_view {
  constructor() {}

  // web admin section

  submit_web_admin_form = (modelFunction) => {
    const website_admin_form = document.getElementById("website_admin_form");

    website_admin_form.addEventListener("submit", (event) => {
      event.preventDefault();

      const password = document.getElementById("website_admin_form_password");

      modelFunction(password.value);
    });
  };

  render_web_admin_form = (state) => {
    const loading_circle = document.getElementById(
      "website_admin_form_loading",
    );

    const err_msg = document.getElementById("website_admin_form_error_msg");

    if (state.web_admin.loading) {
      loading_circle.style.display = "none";
      loading_circle.style.display = "block";
    } else if (state.web_admin.loading === false && state.web_admin.logged_in) {
      loading_circle.style.display = "none";

      err_msg.style.display = "none";

      window.location.href = "/admin.html";
    } else if (
      state.web_admin.loading === false &&
      state.web_admin.failed_login
    ) {
      loading_circle.style.display = "none";

      err_msg.style.display = "none";
      err_msg.style.display = "flex";
    }
  };

  // board members section

  submit_board_members_form = (modelFunction) => {
    const board_members_form = document.getElementById("board_members_form");

    board_members_form.addEventListener("submit", (event) => {
      event.preventDefault();

      const username = document.getElementById("board_members_form_username");
      const password = document.getElementById("board_members_form_password");

      modelFunction(username.value, password.value);
    });
  };

  render_board_members_form = (state) => {
    const loading_circle = document.getElementById(
      "board_members_form_loading",
    );

    const err_msg = document.getElementById("board_members_form_error_msg");

    if (state.board_member_login.loading) {
      loading_circle.style.display = "none";
      loading_circle.style.display = "block";
    } else if (
      state.board_member_login.loading === false &&
      state.board_member_login.logged_in
    ) {
      loading_circle.style.display = "none";

      err_msg.style.display = "none";

      window.location.href = "/board_members.html";
    } else if (
      state.board_member_login.loading === false &&
      state.board_member_login.failed_login
    ) {
      loading_circle.style.display = "none";

      err_msg.style.display = "none";
      err_msg.style.display = "flex";
    }
  };
}
