import { Login_model } from "../model/model.js";
import { Login_view } from "../view/view.js";

export class Login_controller {
  constructor() {
    this.view = new Login_view();
    this.model = new Login_model();

    this.view.submit_web_admin_form(this.controller_submit_web_admin_form);

    this.view.submit_board_members_form(
      this.controller_submit_board_members_form,
    );

    this.model.registerListener((state) => {
      this.view.render_web_admin_form(state);
    });

    this.model.registerListener((state) => {
      this.view.render_board_members_form(state);
    });
  }

  controller_submit_web_admin_form = (password) => {
    this.model.website_admin_login(password);
  };

  controller_submit_board_members_form = (username, password) => {
    this.model.board_member_login(username, password);
  };
}
